#include <openssl/evp.h>

// Assume priv_key is an EVP_PKEY*
// Assume digest is an unsigned char* and digest_len is size_t
// Assume sig is an unsigned char* (buffer for the signature)

EVP_PKEY_CTX *ctx = EVP_PKEY_CTX_new(priv_key, NULL);

if (EVP_PKEY_sign_init(ctx) <= 0) {
    /* Handle error */
}

// Determine signature length
size_t sig_len;
if (EVP_PKEY_sign(ctx, NULL, &sig_len, digest, digest_len) <= 0) {
    /* Handle error */
}

unsigned char *sig = malloc(sig_len);

// Perform the signing
if (EVP_PKEY_sign(ctx, sig, &sig_len, digest, digest_len) <= 0) {
    /* Handle error */
}

EVP_PKEY_CTX_free(ctx);
```

